rows = []
for crd, name, cat, status, rationale, ev in R:
    rows.append({
        "crd": crd, "firm_name": name, "category": cat, "status": status,
        "duplicate_of": None,
        "evidence": [{"class": c, "source_url": u, "observed_at": None,
                      "detail": {"span": s, "category_signal": cat}} for c, u, s in ev],
        "rationale": rationale, "decided_by": DECIDER,
    })

assert len(rows) == 50, f"expected 50, got {len(rows)}"
for r in rows:  # every affirmed row must carry >=2 evidence classes (ADR-0020)
    if r["status"] == "affirmed":
        assert len({e["class"] for e in r["evidence"]}) >= 2, f"{r['crd']} affirmed with <2 classes"
with open("data/curation/entity_adjudications.json", "w", encoding="utf-8") as fh:
    json.dump(rows, fh, indent=1)
print(f"wrote {len(rows)} ratified decisions")
